import React, { useEffect } from 'react'

export default function CartCountInfo({message, onClose}) {

    useEffect(() => {
        if(message){
            const timer = setTimeout(() => {
                onClose()
            }, 3000)
            return () => clearTimeout(timer)
        }

        
    }, [message, onClose])

    if(!message) return null
  return (
    <div style={{
        position: 'fixed',
        top: '0',
        left: '50%'
    }}>
      <span style={{
        padding: '10px',
        backgroundColor: '#2874f0',
        color: "#fff"
      }}>{message}</span>
    </div>
  )
}
